// shadcn
import { Button } from "@/components/ui/button";

// assets
import {
  CloudLightning,
  Globe,
  Layers,
  MonitorSmartphone,
  Puzzle,
  Wind
} from "lucide-react";

// constants
const featureData = [
  {
    title: "Creative Design",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: MonitorSmartphone,
    iconColor: "text-blue-500"
  },
  {
    title: "Quick Result",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: Puzzle,
    iconColor: "text-yellow-500"
  },
  {
    title: "Fast & Easy Work",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: Layers,
    iconColor: "text-green-500"
  },
  {
    title: "Cool Animations",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: CloudLightning,
    iconColor: "text-cyan-500"
  },
  {
    title: "Responsive",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: Globe,
    iconColor: "text-mist-800"
  },
  {
    title: "Clean Code",
    description: "At half-past eight the door opened, the policeman appeared.",
    icon: Wind,
    iconColor: "text-red-500"
  }
];

//  ------------------------------ | FEATURE - 9 | ------------------------------  //

export default function Feature9() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header Section */}
        <div className="mx-auto max-w-2xl text-center mb-16 lg:mb-20">
          <h2 className="mb-6">Main Features</h2>
        </div>

        {/* Features Grid */}
        <div className="grid grid-cols-12 gap-y-6 gap-x-6 mb-16 lg:mb-20">
          {featureData.map((item, index) => (
            <div
              key={index}
              className="col-span-12 md:col-span-4 flex flex-col items-center text-center gap-6"
            >
              <div className={`${item.iconColor} mb-2`}>
                <item.icon size={40} strokeWidth={1.5} />
              </div>
              <h5 className="mb-1">{item.title}</h5>
              <p className="text-muted-foreground max-w-xs">
                {item.description}
              </p>
            </div>
          ))}
        </div>

        {/* Call to Action Section */}
        <div className="flex justify-center">
          <Button size="lg">Order</Button>
        </div>
      </div>
    </section>
  );
}
